import React, { useState } from 'react';
import axios from 'axios';
import ThemeToggle from './ThemeToggle';
import './App.css';

function App() {
  const [code, setCode] = useState('function add(a, b) {\n  return a + b;\n}\n\nadd(1, 3);');
  const[showFiles,setShowFiles] = useState
  const [prompt, setPrompt] = useState('');
  const [messages, setMessages] = useState([]);
  const [loading, setLoading] = useState(false);

  const handleSubmit = async () => {
   

    if (!prompt.trim()) {
      console.log('Missing  prompt');
      setMessages([...messages, { type: 'error', text: 'Please enter prompt!' }]);
      return;
    }

    // Add user message to chat
    const userMessage = { type: 'user', text: prompt };
    setMessages([...messages, userMessage]);

    setLoading(true);
    const currentPrompt = prompt;
    setPrompt('');

    const requestPayload = {
      code,
      prompt: currentPrompt
    };

    console.log(' payload Sending to Backend:', JSON.stringify(requestPayload, null, 2));

    try {
      const response = await axios.post('http://localhost:5000/api/improve-code', requestPayload);

      console.log('✅ Response Received from Backend');
 

      // Update code editor
      setCode(response.data.improvedCode);
      
      // Add AI response to chat
      const aiMessage = { type: 'ai', text: 'Code updated successfully!', code: response.data.improvedCode };
      setMessages([...messages, userMessage, aiMessage]);
      
    } catch (err) {
  
      
      const errorMessage = { type: 'error', text: `Error: ${err.response?.data?.error || err.message}` };
      setMessages([...messages, userMessage, errorMessage]);
    } finally {
      setLoading(false);
      console.log('========== FRONTEND REQUEST COMPLETE ==========\n');
    }
  };

const inputcode = document.querySelector('#inputcode');


  const handleClick = () => {
   
     const selectedText = window.getSelection().toString();

    

  console.log(selectedText);
  };


inputcode?.addEventListener('click', handleClick);
  

  

  return (
    <div className="app-container">
      {showfiles ?(  <div className="chat-panel" >
        <h1>file structure</h1>
      </div>):null}
    
      {/* Left Side - Code Editor */}
      <div className="editor-panel">
        <div className="panel-header">
          <h3>Code Editor</h3>
          <ThemeToggle />
        </div>
        <textarea
          className="code-editor"
          id='inputcode'
          value={code}
          onChange={(e) => setCode(e.target.value)}
          placeholder="Write your code here..."
          spellCheck="false"
        />
      </div>

      {/* Right Side - Chat Panel */}
      <div className="chat-panel">
        <div className="panel-header">
          <h3>AI Assistant</h3>
        </div>
        
        <div className="chat-messages">
          {messages.length === 0 ? (
            <div className="empty-chat">
              <p>👋 Hi! I'm your AI code assistant.</p>
              <p>Ask me to improve, fix, or explain your code!</p>
            </div>
          ) : (
            messages.map((msg, idx) => (
              <div key={idx} className={`message ${msg.type}`}>
                <div className="message-label">
                  {msg.type === 'user' ? '👤 You' : msg.type === 'ai' ? '🤖 AI' : '⚠️ Error'}
                </div>
                <div className="message-text">{msg.text}</div>
              </div>
            ))
          )}
          {loading && (
            <div className="message ai">
              <div className="message-label">🤖 AI</div>
              <div className="message-text loading">Thinking...</div>
            </div>
          )}
        </div>

        <div className="chat-input-section">
          <input
            type="text"
            value={prompt}
            onChange={(e) => setPrompt(e.target.value)}
            placeholder="Ask AI to improve your code..."
            onKeyPress={(e) => e.key === 'Enter' && !loading && handleSubmit()}
            disabled={loading}
          />
          <button onClick={handleSubmit} disabled={loading || !prompt.trim()}>
            {loading ? '⏳' : '🚀'}
          </button>
        </div>
      </div>
    </div>
  );
}

export default App;
